 58вҶ’function resolveFragmentLink(baseDir, href) {
 59вҶ’  if (href.startsWith('knowledge/')) {
 60вҶ’    return path.join(baseDir, href);
 61вҶ’  }
 62вҶ’  if (href.startsWith('./') || href.startsWith('../')) {
 63вҶ’    return path.join(baseDir, href);
 64вҶ’  }
 65вҶ’  // If only a filename is provided, assume knowledge dir
 66вҶ’  if (href.endsWith('.md') && !href.includes('/')) {
