/**
 * Installation Component Tests - SKF Module
 *
 * Tests SKF module installation components in isolation:
 * - Module.yaml structure validation
 * - Agent YAML structure validation
 * - Path references validation
 * - Workflow existence verification
 *
 * These are deterministic unit tests that don't require full installation.
 * Usage: node test/test-installation-components.js
 */

const path = require('node:path');
const fs = require('node:fs/promises');
const yaml = require('js-yaml');

async function pathExists(filePath) {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

// ANSI colors
const colors = {
  reset: '\u001B[0m',
  green: '\u001B[32m',
  red: '\u001B[31m',
  yellow: '\u001B[33m',
  cyan: '\u001B[36m',
  dim: '\u001B[2m',
};

let passed = 0;
let failed = 0;

/**
 * Test helper: Assert condition
 */
function assert(condition, testName, errorMessage = '') {
  if (condition) {
    console.log(`${colors.green}вң“${colors.reset} ${testName}`);
    passed++;
  } else {
    console.log(`${colors.red}вң—${colors.reset} ${testName}`);
    if (errorMessage) {
      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
    }
    failed++;
  }
}

/**
 * Test Suite
 */
async function runTests() {
  console.log(`${colors.cyan}========================================`);
  console.log('SKF Installation Component Tests');
  console.log(`========================================${colors.reset}\n`);

  const projectRoot = path.join(__dirname, '..');

  // ============================================================
  // Test 1: Module.yaml Structure
  // ============================================================
  console.log(
    `${colors.yellow}Test Suite 1: Module Configuration${colors.reset}\n`,
  );

  try {
    const moduleYamlPath = path.join(projectRoot, 'src/module.yaml');
    const moduleYaml = yaml.load(await fs.readFile(moduleYamlPath, 'utf8'));

    assert(moduleYaml.code === 'skf', 'module.yaml has correct code: skf');
    assert(
      typeof moduleYaml.name === 'string' && moduleYaml.name.length > 0,
      'module.yaml has name',
    );
    assert(
      typeof moduleYaml.description === 'string' &&
        moduleYaml.description.length > 0,
      'module.yaml has description',
    );
    assert(
      typeof moduleYaml.default_selected === 'boolean',
      'module.yaml has boolean default_selected',
    );
  } catch (error) {
    assert(false, 'module.yaml loads and validates', error.message);
  }

  console.log('');

  // ============================================================
  // Test 2: SKF Agent YAML Structure
  // ============================================================
  console.log(
    `${colors.yellow}Test Suite 2: SKF Agent Structure${colors.reset}\n`,
  );

  try {
    const skfAgentPath = path.join(projectRoot, 'src/agents/skf.agent.yaml');

    if (await pathExists(skfAgentPath)) {
      const skfAgent = yaml.load(await fs.readFile(skfAgentPath, 'utf8'));

      assert(
        skfAgent.agent !== undefined,
        'skf.agent.yaml has agent root key',
      );
      assert(
        skfAgent.agent.metadata !== undefined,
        'SKF agent has metadata section',
      );
      assert(
        skfAgent.agent.metadata.module === 'skf',
        'SKF agent metadata has module: skf',
      );
      assert(
        skfAgent.agent.metadata.id.includes('_bmad/skf/'),
        'SKF agent id references _bmad/skf/ path',
      );
      assert(
        skfAgent.agent.persona !== undefined,
        'SKF agent has persona section',
      );
      assert(
        skfAgent.agent.critical_actions !== undefined,
        'SKF agent has critical_actions',
      );
      assert(skfAgent.agent.menu !== undefined, 'SKF agent has menu');
      assert(
        Array.isArray(skfAgent.agent.menu) && skfAgent.agent.menu.length === 11,
        'SKF agent menu has 11 workflows',
        `Found ${Array.isArray(skfAgent.agent.menu) ? skfAgent.agent.menu.length : 'non-array'}`,
      );

      // Verify no foreign module references
      const yamlContent = await fs.readFile(skfAgentPath, 'utf8');
      assert(
        !yamlContent.includes('module: tea'),
        'SKF agent has no module: tea references',
      );
      assert(
        !yamlContent.includes('module: bmm'),
        'SKF agent has no module: bmm references',
      );
    } else {
      assert(
        false,
        'SKF agent YAML exists',
        'src/agents/skf.agent.yaml not found',
      );
    }
  } catch (error) {
    assert(false, 'SKF agent structure validates', error.message);
  }

  console.log('');

  // ============================================================
  // Test 3: Knowledge Base Structure
  // ============================================================
  console.log(
    `${colors.yellow}Test Suite 3: Knowledge Base${colors.reset}\n`,
  );

  try {
    const skfIndexPath = path.join(
      projectRoot,
      'src/knowledge/skf-knowledge-index.csv',
    );

    if (await pathExists(skfIndexPath)) {
      const csvContent = await fs.readFile(skfIndexPath, 'utf8');
      const lines = csvContent.trim().split('\n');

      assert(
        lines.length >= 2,
        'skf-knowledge-index.csv has header + at least 1 record',
        `Found ${lines.length} lines`,
      );
      assert(
        lines[0].includes('id,name,description,tags,tier,fragment_file'),
        'skf-knowledge-index.csv has correct header format',
      );
    } else {
      assert(
        false,
        'Knowledge index exists',
        'src/knowledge/skf-knowledge-index.csv not found',
      );
    }
  } catch (error) {
    assert(false, 'Knowledge base structure validates', error.message);
  }

  console.log('');

  // ============================================================
  // Test 4: Workflow Structure
  // ============================================================
  console.log(
    `${colors.yellow}Test Suite 4: Workflow Structure${colors.reset}\n`,
  );

  const workflowNames = [
    'setup-forge',
    'analyze-source',
    'brief-skill',
    'create-skill',
    'quick-skill',
    'create-stack-skill',
    'update-skill',
    'audit-skill',
    'test-skill',
    'export-skill',
  ];

  for (const workflowName of workflowNames) {
    const workflowPath = path.join(
      projectRoot,
      `src/workflows/${workflowName}/workflow.md`,
    );

    if (await pathExists(workflowPath)) {
      const content = await fs.readFile(workflowPath, 'utf8');
      assert(content.length > 0, `${workflowName}/workflow.md exists`);
    } else {
      assert(
        false,
        `${workflowName}/workflow.md exists`,
        `src/workflows/${workflowName}/workflow.md not found`,
      );
    }
  }

  console.log('');

  // ============================================================
  // Summary
  // ============================================================
  console.log(`${colors.cyan}========================================`);
  console.log('Test Results:');
  console.log(`  Passed: ${colors.green}${passed}${colors.reset}`);
  console.log(`  Failed: ${colors.red}${failed}${colors.reset}`);
  console.log(`========================================${colors.reset}\n`);

  if (failed === 0) {
    console.log(
      `${colors.green}вңЁ All installation component tests passed!${colors.reset}\n`,
    );
    process.exit(0);
  } else {
    console.log(
      `${colors.red}вқҢ Some installation component tests failed${colors.reset}\n`,
    );
    process.exit(1);
  }
}

// Run tests
runTests().catch((error) => {
  console.error(
    `${colors.red}Test runner failed:${colors.reset}`,
    error.message,
  );
  console.error(error.stack);
  process.exit(1);
});

