435вҶ’// =============================================================================
436вҶ’// Post-build Injection
437вҶ’/**
438вҶ’ * Recursively collects all files with the given extension under a directory.
439вҶ’ *
440вҶ’ * @param {string} dir - Root directory to search.
441вҶ’ * @param {string} ext - File extension to match (include the leading dot, e.g. ".md").
442вҶ’ * @returns {string[]} An array of file paths for files ending with `ext` found under `dir`.
443вҶ’ */
444вҶ’
445вҶ’function getAllFilesByExtension(dir, ext) {
446вҶ’  const result = [];
447вҶ’  const entries = fs.readdirSync(dir, { withFileTypes: true });
448вҶ’
449вҶ’  for (const entry of entries) {
450вҶ’    const fullPath = path.join(dir, entry.name);
451вҶ’    if (entry.isDirectory()) {
452вҶ’      result.push(...getAllFilesByExtension(fullPath, ext));
453вҶ’    } else if (entry.name.endsWith(ext)) {
454вҶ’      result.push(fullPath);
455вҶ’    }
456вҶ’  }
457вҶ’
458вҶ’  return result;
459вҶ’}
