463вҶ’/**
464вҶ’ * Remove any existing build output and recreate the build directory.
465вҶ’ *
466вҶ’ * Ensures the configured BUILD_DIR is empty by deleting it if present and then creating a fresh directory.
467вҶ’ */
468вҶ’
469вҶ’function cleanBuildDirectory() {
470вҶ’  console.log('Cleaning previous build...');
471вҶ’
472вҶ’  if (fs.existsSync(BUILD_DIR)) {
