478вҶ’/**
479вҶ’ * Recursively copies all files and subdirectories from one directory to another, creating the destination if needed.
480вҶ’ *
481вҶ’ * @param {string} src - Path to the source directory to copy from.
482вҶ’ * @param {string} dest - Path to the destination directory to copy to.
483вҶ’ * @param {string[]} [exclude=[]] - List of file or directory names (not paths) to skip while copying.
484вҶ’ * @returns {boolean} `true` if the source existed and copying proceeded, `false` if the source did not exist.
485вҶ’ */
486вҶ’function copyDirectory(src, dest, exclude = []) {
487вҶ’  if (!fs.existsSync(src)) return false;
488вҶ’  fs.mkdirSync(dest, { recursive: true });
489вҶ’
490вҶ’  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
491вҶ’    if (exclude.includes(entry.name)) continue;
492вҶ’
493вҶ’    const srcPath = path.join(src, entry.name);
494вҶ’    const destPath = path.join(dest, entry.name);
495вҶ’
496вҶ’    if (entry.isDirectory()) {
497вҶ’      copyDirectory(srcPath, destPath, exclude);
498вҶ’    } else {
499вҶ’      fs.copyFileSync(srcPath, destPath);
500вҶ’    }
501вҶ’  }
502вҶ’  return true;
503вҶ’}
504вҶ’
505вҶ’/**
506вҶ’ * Create a ZIP archive of a directory, optionally excluding entries that match given substrings.
507вҶ’ * @param {string} sourceDir - Path to the source directory to archive.
508вҶ’ * @param {string} outputPath - Path to write the resulting ZIP file.
509вҶ’ * @param {string[]} [exclude=[]] - Array of substrings; any entry whose path includes one of these substrings will be omitted.
510вҶ’ * @returns {Promise<void>} Resolves when the archive has been fully written and closed, rejects on error.
511вҶ’ */
512вҶ’function createZipArchive(sourceDir, outputPath, exclude = []) {
513вҶ’  return new Promise((resolve, reject) => {
514вҶ’    const output = fs.createWriteStream(outputPath);
515вҶ’    const archive = archiver('zip', { zlib: { level: 9 } });
516вҶ’
517вҶ’    output.on('close', resolve);
518вҶ’    archive.on('error', reject);
519вҶ’
520вҶ’    archive.pipe(output);
521вҶ’
522вҶ’    const baseName = path.basename(sourceDir);
523вҶ’    archive.directory(sourceDir, baseName, (entry) => {
524вҶ’      for (const pattern of exclude) {
525вҶ’        if (entry.name.includes(pattern)) return false;
526вҶ’      }
527вҶ’      return entry;
528вҶ’    });
529вҶ’
530вҶ’    archive.finalize();
531вҶ’  });
532вҶ’}
