 1вҶ’/**
 2вҶ’ * Resolve the site's base URL using cascading environment defaults.
 3вҶ’ *
 4вҶ’ * Preference order: use SITE_URL if set; otherwise derive a GitHub Pages URL from GITHUB_REPOSITORY; otherwise use the local development URL.
 5вҶ’ * @returns {string} The resolved site URL (SITE_URL override, or `https://{owner}.github.io/{repo}`, or `http://localhost:3000`).
 6вҶ’ */
 7вҶ’export function getSiteUrl() {
 8вҶ’  // Explicit override (works in both local and GitHub Actions)
 9вҶ’  if (process.env.SITE_URL) {
10вҶ’    return process.env.SITE_URL;
11вҶ’  }
12вҶ’
13вҶ’  // GitHub Actions: compute from repository context
14вҶ’  if (process.env.GITHUB_REPOSITORY) {
15вҶ’    const parts = process.env.GITHUB_REPOSITORY.split('/');
16вҶ’    if (parts.length !== 2 || !parts[0] || !parts[1]) {
17вҶ’      throw new Error(`Invalid GITHUB_REPOSITORY format: "${process.env.GITHUB_REPOSITORY}". Expected "owner/repo".`);
18вҶ’    }
19вҶ’    const [owner, repo] = parts;
20вҶ’    return `https://${owner}.github.io/${repo}`;
21вҶ’  }
22вҶ’
23вҶ’  // Local development: use dev server
24вҶ’  return 'http://localhost:3000';
25вҶ’}
