  1вҶ’/**
  2вҶ’ * Rehype plugin to transform markdown file links (.md) to page routes
  3вҶ’ *
  4вҶ’ * Transforms:
  5вҶ’ *   ./path/to/file.md вҶ’ ./path/to/file/
  6вҶ’ *   ./path/index.md вҶ’ ./path/ (index.md becomes directory root)
  7вҶ’ *   ../path/file.md#anchor вҶ’ ../path/file/#anchor
  8вҶ’ *   ./file.md?query=param вҶ’ ./file/?query=param
  9вҶ’ *   /docs/absolute/path/file.md вҶ’ {base}/absolute/path/file/
 10вҶ’ *
 11вҶ’ * For absolute paths starting with /docs/, the /docs prefix is stripped
 12вҶ’ * since the Astro site serves content from the docs directory as the root.
 13вҶ’ * The base path is prepended to absolute paths for subdirectory deployments.
 14вҶ’ *
 15вҶ’ * Affects relative links (./, ../) and absolute paths (/) - external links are unchanged
 16вҶ’ */
 17вҶ’
 18вҶ’import { visit } from 'unist-util-visit';
 19вҶ’
 20вҶ’/**
 21вҶ’ * Convert Markdown file links (.md) into equivalent page route-style links.
 22вҶ’ *
 23вҶ’ * The returned transformer walks the HTML tree and rewrites anchor `href` values that are relative paths (./, ../) or absolute paths (/) pointing to `.md` files. It preserves query strings and hash anchors, rewrites `.../index.md` to the directory root path (`.../`), and rewrites other `.md` file paths by removing the `.md` extension and ensuring a trailing slash. External links (http://, https://) and non-.md links are left unchanged.
 24вҶ’ *
 25вҶ’ * @param {Object} options - Plugin options
 26вҶ’ * @param {string} options.base - The base path to prepend to absolute URLs (e.g., '/BMAD-METHOD/')
 27вҶ’ * @returns {function} A HAST tree transformer that mutates `a` element `href` properties as described.
 28вҶ’ */
 29вҶ’export default function rehypeMarkdownLinks(options = {}) {
 30вҶ’  const base = options.base || '/';
 31вҶ’  // Normalize base: ensure it ends with / and doesn't have double slashes
 32вҶ’  const normalizedBase = base === '/' ? '' : base.endsWith('/') ? base.slice(0, -1) : base;
 33вҶ’
 34вҶ’  return (tree) => {
 35вҶ’    visit(tree, 'element', (node) => {
 36вҶ’      // Only process anchor tags with href
 37вҶ’      if (node.tagName !== 'a' || !node.properties?.href) {
 38вҶ’        return;
 39вҶ’      }
 40вҶ’
 41вҶ’      const href = node.properties.href;
 42вҶ’
 43вҶ’      // Skip if not a string (shouldn't happen, but be safe)
 44вҶ’      if (typeof href !== 'string') {
 45вҶ’        return;
 46вҶ’      }
 47вҶ’
 48вҶ’      // Skip external links (http://, https://, mailto:, etc.)
 49вҶ’      if (href.includes('://') || href.startsWith('mailto:') || href.startsWith('tel:')) {
 50вҶ’        return;
 51вҶ’      }
 52вҶ’
 53вҶ’      // Only transform paths starting with ./, ../, or / (absolute)
 54вҶ’      if (!href.startsWith('./') && !href.startsWith('../') && !href.startsWith('/')) {
 55вҶ’        return;
 56вҶ’      }
 57вҶ’
 58вҶ’      // Extract path portion (before ? and #) to check if it's a .md file
 59вҶ’      const firstDelimiter = Math.min(
 60вҶ’        href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
 61вҶ’        href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
 62вҶ’      );
 63вҶ’      const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
 64вҶ’
 65вҶ’      // Don't transform if path doesn't end with .md
 66вҶ’      if (!pathPortion.endsWith('.md')) {
 67вҶ’        return;
 68вҶ’      }
 69вҶ’
 70вҶ’      // Split the URL into parts: path, anchor, and query
 71вҶ’      let urlPath = pathPortion;
 72вҶ’      let anchor = '';
 73вҶ’      let query = '';
 74вҶ’
 75вҶ’      // Extract query string and anchor from original href
 76вҶ’      if (firstDelimiter !== Infinity) {
 77вҶ’        const suffix = href.substring(firstDelimiter);
 78вҶ’        const anchorInSuffix = suffix.indexOf('#');
 79вҶ’        if (suffix.startsWith('?')) {
 80вҶ’          if (anchorInSuffix !== -1) {
 81вҶ’            query = suffix.substring(0, anchorInSuffix);
 82вҶ’            anchor = suffix.substring(anchorInSuffix);
 83вҶ’          } else {
 84вҶ’            query = suffix;
 85вҶ’          }
 86вҶ’        } else {
 87вҶ’          // starts with #
 88вҶ’          anchor = suffix;
 89вҶ’        }
 90вҶ’      }
 91вҶ’
 92вҶ’      // Track if this was an absolute path (for base path prepending)
 93вҶ’      const isAbsolute = urlPath.startsWith('/');
 94вҶ’
 95вҶ’      // Strip /docs/ prefix from absolute paths (repo-relative вҶ’ site-relative)
 96вҶ’      if (urlPath.startsWith('/docs/')) {
 97вҶ’        urlPath = urlPath.slice(5); // Remove '/docs' prefix, keeping the leading /
 98вҶ’      }
 99вҶ’
100вҶ’      // Transform .md to /
101вҶ’      // Special case: index.md вҶ’ directory root (e.g., ./tutorials/index.md вҶ’ ./tutorials/)
102вҶ’      if (urlPath.endsWith('/index.md')) {
103вҶ’        urlPath = urlPath.replace(/\/index\.md$/, '/');
104вҶ’      } else {
105вҶ’        urlPath = urlPath.replace(/\.md$/, '/');
106вҶ’      }
107вҶ’
108вҶ’      // Prepend base path to absolute URLs for subdirectory deployments
109вҶ’      if (isAbsolute && normalizedBase) {
110вҶ’        urlPath = normalizedBase + urlPath;
111вҶ’      }
112вҶ’
113вҶ’      // Reconstruct the href
114вҶ’      node.properties.href = urlPath + query + anchor;
115вҶ’    });
116вҶ’  };
117вҶ’}
