  1вҶ’/**
  2вҶ’ * Documentation Link Validator
  3вҶ’ *
  4вҶ’ * Validates site-relative links in markdown files and attempts to fix broken ones.
  5вҶ’ *
  6вҶ’ * What it checks:
  7вҶ’ * - All site-relative links (starting with /) point to existing .md files
  8вҶ’ * - Anchor links (#section) point to valid headings
  9вҶ’ *
 10вҶ’ * What it fixes:
 11вҶ’ * - Broken links where the target file can be found elsewhere in /docs
 12вҶ’ *
 13вҶ’ * Usage:
 14вҶ’ *   node tools/validate-doc-links.js           # Dry run (validate and show issues)
 15вҶ’ *   node tools/validate-doc-links.js --write   # Fix auto-fixable issues
 16вҶ’ */
 17вҶ’
 18вҶ’const fs = require('node:fs');
 19вҶ’const path = require('node:path');
 20вҶ’
 21вҶ’const DOCS_ROOT = path.resolve(__dirname, '../docs');
 22вҶ’const DRY_RUN = !process.argv.includes('--write');
 23вҶ’
 24вҶ’// Regex to match markdown links with site-relative paths
 25вҶ’const LINK_REGEX = /\[([^\]]*)\]\((\/[^)]+)\)/g;
 26вҶ’
 27вҶ’// File extensions that are static assets, not markdown docs
 28вҶ’const STATIC_ASSET_EXTENSIONS = ['.zip', '.txt', '.pdf', '.png', '.jpg', '.jpeg', '.gif', '.svg', '.webp', '.ico'];
 29вҶ’
 30вҶ’// Custom Astro page routes (not part of the docs content collection)
 31вҶ’const CUSTOM_PAGE_ROUTES = new Set([]);
 32вҶ’
 33вҶ’// Regex to extract headings for anchor validation
 34вҶ’const HEADING_PATTERN = /^#{1,6}\s+(.+)$/gm;
 35вҶ’
 36вҶ’/**
 37вҶ’ * Get all markdown files in docs directory, excluding _* directories/files
 38вҶ’ */
 39вҶ’function getMarkdownFiles(dir) {
 40вҶ’  const files = [];
 41вҶ’
 42вҶ’  function walk(currentDir) {
 43вҶ’    const entries = fs.readdirSync(currentDir, { withFileTypes: true });
 44вҶ’
 45вҶ’    for (const entry of entries) {
 46вҶ’      const fullPath = path.join(currentDir, entry.name);
 47вҶ’
 48вҶ’      if (entry.name.startsWith('_')) {
 49вҶ’        continue;
 50вҶ’      }
 51вҶ’
 52вҶ’      if (entry.isDirectory()) {
 53вҶ’        walk(fullPath);
 54вҶ’      } else if (entry.isFile() && entry.name.endsWith('.md')) {
 55вҶ’        files.push(fullPath);
 56вҶ’      }
 57вҶ’    }
 58вҶ’  }
 59вҶ’
 60вҶ’  walk(dir);
 61вҶ’  return files;
 62вҶ’}
 63вҶ’
 64вҶ’/**
 65вҶ’ * Strip fenced code blocks from content
 66вҶ’ */
 67вҶ’function stripCodeBlocks(content) {
 68вҶ’  return content.replaceAll(/```[\s\S]*?```/g, '');
 69вҶ’}
 70вҶ’
 71вҶ’/**
 72вҶ’ * Convert a heading to its anchor slug
 73вҶ’ */
 74вҶ’function headingToAnchor(heading) {
 75вҶ’  return heading
 76вҶ’    .toLowerCase()
 77вҶ’    .replaceAll(/[\u{1F300}-\u{1F9FF}]/gu, '') // Remove emojis
 78вҶ’    .replaceAll(/[^\w\s-]/g, '') // Remove special chars
 79вҶ’    .replaceAll(/\s+/g, '-') // Spaces to hyphens
 80вҶ’    .replaceAll(/-+/g, '-') // Collapse hyphens
 81вҶ’    .replaceAll(/^-+|-+$/g, ''); // Trim hyphens
 82вҶ’}
 83вҶ’
 84вҶ’/**
 85вҶ’ * Extract anchor slugs from a markdown file
 86вҶ’ */
 87вҶ’function extractAnchors(content) {
 88вҶ’  const anchors = new Set();
 89вҶ’  let match;
 90вҶ’
 91вҶ’  HEADING_PATTERN.lastIndex = 0;
 92вҶ’  while ((match = HEADING_PATTERN.exec(content)) !== null) {
 93вҶ’    const headingText = match[1]
 94вҶ’      .trim()
 95вҶ’      .replaceAll(/`([^`]+)`/g, '$1')
 96вҶ’      .replaceAll(/\*\*([^*]+)\*\*/g, '$1')
 97вҶ’      .replaceAll(/\*([^*]+)\*/g, '$1')
 98вҶ’      .replaceAll(/\[([^\]]+)\]\([^)]+\)/g, '$1')
 99вҶ’      .trim();
100вҶ’    anchors.add(headingToAnchor(headingText));
101вҶ’  }
102вҶ’
103вҶ’  return anchors;
104вҶ’}
105вҶ’
106вҶ’/**
107вҶ’ * Resolve a site-relative link to a file path
108вҶ’ * /docs/how-to/installation/install-bmad.md -> docs/how-to/installation/install-bmad.md
109вҶ’ * /how-to/installation/install-bmad/ -> docs/how-to/installation/install-bmad.md or .../index.md
110вҶ’ */
111вҶ’function resolveLink(siteRelativePath) {
112вҶ’  // Strip anchor and query
113вҶ’  let checkPath = siteRelativePath.split('#')[0].split('?')[0];
114вҶ’
115вҶ’  // Strip /docs/ prefix if present (repo-relative links)
116вҶ’  if (checkPath.startsWith('/docs/')) {
117вҶ’    checkPath = checkPath.slice(5); // Remove '/docs' but keep leading '/'
118вҶ’  }
119вҶ’
120вҶ’  if (checkPath.endsWith('/')) {
121вҶ’    // Could be file.md or directory/index.md
122вҶ’    const asFile = path.join(DOCS_ROOT, checkPath.slice(0, -1) + '.md');
123вҶ’    const asIndex = path.join(DOCS_ROOT, checkPath, 'index.md');
124вҶ’
125вҶ’    if (fs.existsSync(asFile)) return asFile;
126вҶ’    if (fs.existsSync(asIndex)) return asIndex;
127вҶ’    return null;
128вҶ’  }
129вҶ’
130вҶ’  // Direct path (e.g., /path/file.md)
131вҶ’  const direct = path.join(DOCS_ROOT, checkPath);
132вҶ’  if (fs.existsSync(direct)) return direct;
133вҶ’
134вҶ’  // Try with .md extension
135вҶ’  const withMd = direct + '.md';
136вҶ’  if (fs.existsSync(withMd)) return withMd;
137вҶ’
138вҶ’  return null;
139вҶ’}
140вҶ’
141вҶ’/**
142вҶ’ * Search for a file with directory context
143вҶ’ */
144вҶ’function findFileWithContext(brokenPath) {
145вҶ’  // Extract filename and parent directory from the broken path
146вҶ’  // e.g., /tutorials/getting-started/foo/ -> parent: getting-started, file: foo.md
147вҶ’  const cleanPath = brokenPath.replace(/\/$/, '').replace(/^\//, '');
148вҶ’  const parts = cleanPath.split('/');
149вҶ’  const fileName = parts.at(-1) + '.md';
150вҶ’  const parentDir = parts.length > 1 ? parts.at(-2) : null;
151вҶ’
152вҶ’  const allFiles = getMarkdownFiles(DOCS_ROOT);
153вҶ’  const matches = [];
154вҶ’
155вҶ’  for (const file of allFiles) {
156вҶ’    const fileBaseName = path.basename(file);
157вҶ’    const fileParentDir = path.basename(path.dirname(file));
158вҶ’
159вҶ’    // Exact filename match with parent directory context
160вҶ’    if (fileBaseName === fileName) {
161вҶ’      if (parentDir && fileParentDir === parentDir) {
162вҶ’        // Strong match: both filename and parent dir match
163вҶ’        return [file];
164вҶ’      }
165вҶ’      matches.push(file);
166вҶ’    }
167вҶ’
168вҶ’    // Also check for index.md in a matching directory
169вҶ’    if (fileBaseName === 'index.md' && fileParentDir === fileName.replace('.md', '')) {
170вҶ’      matches.push(file);
171вҶ’    }
172вҶ’  }
173вҶ’
174вҶ’  return matches;
175вҶ’}
176вҶ’
177вҶ’/**
178вҶ’ * Convert absolute file path to site-relative URL
179вҶ’ */
180вҶ’function fileToSiteRelative(filePath) {
181вҶ’  let relative = '/' + path.relative(DOCS_ROOT, filePath);
182вҶ’  relative = relative.split(path.sep).join('/');
183вҶ’
184вҶ’  if (relative.endsWith('/index.md')) {
185вҶ’    return relative.replace(/\/index\.md$/, '/');
186вҶ’  }
187вҶ’  return relative.replace(/\.md$/, '/');
188вҶ’}
189вҶ’
190вҶ’/**
191вҶ’ * Process a single file and find issues
192вҶ’ */
193вҶ’function processFile(filePath) {
194вҶ’  const content = fs.readFileSync(filePath, 'utf-8');
195вҶ’  const strippedContent = stripCodeBlocks(content);
196вҶ’  const issues = [];
197вҶ’
198вҶ’  let match;
199вҶ’  LINK_REGEX.lastIndex = 0;
200вҶ’
201вҶ’  while ((match = LINK_REGEX.exec(strippedContent)) !== null) {
202вҶ’    const linkText = match[1];
203вҶ’    const href = match[2];
204вҶ’
205вҶ’    // Extract path and anchor
206вҶ’    const hashIndex = href.indexOf('#');
207вҶ’    const linkPath = hashIndex === -1 ? href : href.slice(0, hashIndex);
208вҶ’    const anchor = hashIndex === -1 ? null : href.slice(hashIndex + 1);
209вҶ’
210вҶ’    // Skip static asset links (zip, txt, images, etc.)
211вҶ’    const linkLower = linkPath.toLowerCase();
212вҶ’    if (STATIC_ASSET_EXTENSIONS.some((ext) => linkLower.endsWith(ext))) {
213вҶ’      continue;
214вҶ’    }
215вҶ’
216вҶ’    // Skip custom Astro page routes
217вҶ’    if (CUSTOM_PAGE_ROUTES.has(linkPath)) {
218вҶ’      continue;
219вҶ’    }
220вҶ’
221вҶ’    // Validate the link target exists
222вҶ’    const targetFile = resolveLink(linkPath);
223вҶ’
224вҶ’    if (!targetFile) {
225вҶ’      // Link is broken - try to find the file
226вҶ’      const candidates = findFileWithContext(linkPath);
227вҶ’
228вҶ’      const issue = {
229вҶ’        type: 'broken-link',
230вҶ’        linkText,
231вҶ’        href,
232вҶ’        linkPath,
233вҶ’        fullMatch: match[0],
234вҶ’      };
235вҶ’
236вҶ’      if (candidates.length === 1) {
237вҶ’        issue.status = 'auto-fixable';
238вҶ’        issue.suggestedFix = fileToSiteRelative(candidates[0]) + (anchor ? '#' + anchor : '');
239вҶ’        issue.foundAt = path.relative(DOCS_ROOT, candidates[0]);
240вҶ’      } else if (candidates.length > 1) {
241вҶ’        issue.status = 'needs-review';
242вҶ’        issue.candidates = candidates.map((c) => path.relative(DOCS_ROOT, c));
243вҶ’      } else {
244вҶ’        issue.status = 'manual-check';
245вҶ’      }
246вҶ’
247вҶ’      issues.push(issue);
248вҶ’      continue;
249вҶ’    }
250вҶ’
251вҶ’    // Validate anchor if present
252вҶ’    if (anchor) {
253вҶ’      const targetContent = fs.readFileSync(targetFile, 'utf-8');
254вҶ’      const anchors = extractAnchors(targetContent);
255вҶ’
256вҶ’      if (!anchors.has(anchor)) {
257вҶ’        issues.push({
258вҶ’          type: 'broken-anchor',
259вҶ’          linkText,
260вҶ’          href,
261вҶ’          anchor,
262вҶ’          status: 'manual-check',
263вҶ’          message: `Anchor "#${anchor}" not found`,
264вҶ’        });
265вҶ’      }
266вҶ’    }
267вҶ’  }
268вҶ’
269вҶ’  return { content, issues };
270вҶ’}
271вҶ’
272вҶ’/**
273вҶ’ * Apply fixes to file content
274вҶ’ */
275вҶ’function applyFixes(content, issues) {
276вҶ’  let updated = content;
277вҶ’
278вҶ’  for (const issue of issues) {
279вҶ’    if (issue.status === 'auto-fixable' && issue.suggestedFix) {
280вҶ’      const oldLink = `[${issue.linkText}](${issue.href})`;
281вҶ’      const newLink = `[${issue.linkText}](${issue.suggestedFix})`;
282вҶ’      updated = updated.replaceAll(oldLink, newLink);
283вҶ’    }
284вҶ’  }
285вҶ’
286вҶ’  return updated;
287вҶ’}
288вҶ’
289вҶ’// Main execution
