  1вҶ’/**
  2вҶ’ * Fix Documentation Links
  3вҶ’ *
  4вҶ’ * Converts relative markdown links to repo-relative paths with .md extension.
  5вҶ’ * This ensures links work both in GitHub and on the Astro/Starlight site
  6вҶ’ * (the rehype plugin transforms /docs/path/file.md вҶ’ /path/file/ at build time).
  7вҶ’ *
  8вҶ’ * - ./file.md вҶ’ /docs/current/path/file.md
  9вҶ’ * - ../other/file.md вҶ’ /docs/resolved/path/file.md
 10вҶ’ * - /path/file/ вҶ’ /docs/path/file.md (or /docs/path/file/index.md if it's a directory)
 11вҶ’ *
 12вҶ’ * Usage:
 13вҶ’ *   node tools/fix-doc-links.js           # Dry run (shows what would change)
 14вҶ’ *   node tools/fix-doc-links.js --write   # Actually write changes
 15вҶ’ */
 16вҶ’
 17вҶ’const fs = require('node:fs');
 18вҶ’const path = require('node:path');
 19вҶ’
 20вҶ’const DOCS_ROOT = path.resolve(__dirname, '../docs');
 21вҶ’const DRY_RUN = !process.argv.includes('--write');
 22вҶ’
 23вҶ’// Regex to match markdown links:
 24вҶ’// - [text](path.md) or [text](path.md#anchor) - existing .md links
 25вҶ’// - [text](/path/to/page/) or [text](/path/to/page/#anchor) - site-relative links to convert
 26вҶ’const MARKDOWN_LINK_REGEX = /\[([^\]]*)\]\(([^)]+(?:\.md|\/))(?:#[^)]*)?(?:\?[^)]*)?\)/g;
 27вҶ’// Simpler approach: match all markdown links and filter in the handler
 28вҶ’const ALL_MARKDOWN_LINKS_REGEX = /\[([^\]]*)\]\(([^)]+)\)/g;
 29вҶ’
 30вҶ’/**
 31вҶ’ * Get all markdown files in docs directory, excluding _* directories/files
 32вҶ’ */
 33вҶ’function getMarkdownFiles(dir) {
 34вҶ’  const files = [];
 35вҶ’
 36вҶ’  function walk(currentDir) {
 37вҶ’    const entries = fs.readdirSync(currentDir, { withFileTypes: true });
 38вҶ’
 39вҶ’    for (const entry of entries) {
 40вҶ’      const fullPath = path.join(currentDir, entry.name);
 41вҶ’
 42вҶ’      // Skip underscore-prefixed entries
 43вҶ’      if (entry.name.startsWith('_')) {
 44вҶ’        continue;
 45вҶ’      }
 46вҶ’
 47вҶ’      if (entry.isDirectory()) {
 48вҶ’        walk(fullPath);
 49вҶ’      } else if (entry.isFile() && entry.name.endsWith('.md')) {
 50вҶ’        files.push(fullPath);
 51вҶ’      }
 52вҶ’    }
 53вҶ’  }
 54вҶ’
 55вҶ’  walk(dir);
 56вҶ’  return files;
 57вҶ’}
 58вҶ’
 59вҶ’/**
 60вҶ’ * Convert a markdown link href to repo-relative path with .md extension
 61вҶ’ *
 62вҶ’ * @param {string} href - The original href (e.g., "./file.md", "/path/to/page/", "/path/to/page/#anchor")
 63вҶ’ * @param {string} currentFilePath - Absolute path to the file containing this link
 64вҶ’ * @returns {string|null} - Repo-relative path (e.g., "/docs/path/to/file.md"), or null if shouldn't be converted
 65вҶ’ */
 66вҶ’function convertToRepoRelative(href, currentFilePath) {
 67вҶ’  // Skip external links
 68вҶ’  if (href.includes('://') || href.startsWith('mailto:') || href.startsWith('tel:')) {
 69вҶ’    return null;
 70вҶ’  }
 71вҶ’
 72вҶ’  // Skip anchor-only links
 73вҶ’  if (href.startsWith('#')) {
 74вҶ’    return null;
 75вҶ’  }
 76вҶ’
 77вҶ’  // Extract anchor and query string if present
 78вҶ’  let anchor = '';
 79вҶ’  let query = '';
 80вҶ’  let pathPortion = href;
 81вҶ’
 82вҶ’  const hashIndex = href.indexOf('#');
 83вҶ’  const queryIndex = href.indexOf('?');
 84вҶ’
 85вҶ’  if (hashIndex !== -1 || queryIndex !== -1) {
 86вҶ’    const firstDelimiter = Math.min(hashIndex === -1 ? Infinity : hashIndex, queryIndex === -1 ? Infinity : queryIndex);
 87вҶ’    pathPortion = href.slice(0, Math.max(0, firstDelimiter));
 88вҶ’
 89вҶ’    const suffix = href.slice(Math.max(0, firstDelimiter));
 90вҶ’    const anchorInSuffix = suffix.indexOf('#');
 91вҶ’
 92вҶ’    if (suffix.startsWith('?')) {
 93вҶ’      if (anchorInSuffix === -1) {
 94вҶ’        query = suffix;
 95вҶ’      } else {
 96вҶ’        query = suffix.slice(0, Math.max(0, anchorInSuffix));
 97вҶ’        anchor = suffix.slice(Math.max(0, anchorInSuffix));
 98вҶ’      }
 99вҶ’    } else {
100вҶ’      anchor = suffix;
101вҶ’    }
102вҶ’  }
103вҶ’
104вҶ’  // Skip non-documentation links (images, external assets, etc.)
105вҶ’  const ext = path.extname(pathPortion).toLowerCase();
106вҶ’  if (
107вҶ’    ext &&
108вҶ’    ext !== '.md' &&
109вҶ’    !['.md'].includes(ext) && // Has an extension that's not .md - skip unless it's a trailing slash path
110вҶ’    !pathPortion.endsWith('/')
111вҶ’  ) {
112вҶ’    return null;
113вҶ’  }
114вҶ’
115вҶ’  // Check if original path ends with / (directory reference) BEFORE path.join normalizes it
116вҶ’  const isDirectoryPath = pathPortion.endsWith('/');
117вҶ’
118вҶ’  let absolutePath;
119вҶ’
120вҶ’  if (pathPortion.startsWith('/docs/')) {
121вҶ’    // Already repo-relative with /docs/ prefix
122вҶ’    absolutePath = path.join(path.dirname(DOCS_ROOT), pathPortion);
123вҶ’  } else if (pathPortion.startsWith('/')) {
124вҶ’    // Site-relative (e.g., /tutorials/getting-started/) - resolve from docs root
125вҶ’    absolutePath = path.join(DOCS_ROOT, pathPortion);
126вҶ’  } else {
127вҶ’    // Relative path (./, ../, or bare filename) - resolve from current file's directory
128вҶ’    const currentDir = path.dirname(currentFilePath);
129вҶ’    absolutePath = path.resolve(currentDir, pathPortion);
130вҶ’  }
131вҶ’
132вҶ’  // Convert to repo-relative path (with /docs/ prefix)
133вҶ’  let repoRelative = '/docs/' + path.relative(DOCS_ROOT, absolutePath);
134вҶ’
135вҶ’  // Normalize path separators for Windows
136вҶ’  repoRelative = repoRelative.split(path.sep).join('/');
137вҶ’
138вҶ’  // If original path was a directory reference (ended with /), check for index.md or file.md
139вҶ’  if (isDirectoryPath) {
140вҶ’    const relativeDir = repoRelative.slice(6); // Remove '/docs/'
141вҶ’
142вҶ’    // Handle root path case (relativeDir is empty or just '.')
143вҶ’    const normalizedDir = relativeDir === '' || relativeDir === '.' ? '' : relativeDir;
144вҶ’    const indexPath = path.join(DOCS_ROOT, normalizedDir, 'index.md');
145вҶ’    const filePath = normalizedDir ? path.join(DOCS_ROOT, normalizedDir + '.md') : null;
146вҶ’
147вҶ’    if (fs.existsSync(indexPath)) {
148вҶ’      // Avoid double slash when repoRelative is '/docs/' (root case)
149вҶ’      repoRelative = repoRelative.endsWith('/') ? repoRelative + 'index.md' : repoRelative + '/index.md';
150вҶ’    } else if (filePath && fs.existsSync(filePath)) {
151вҶ’      repoRelative = repoRelative + '.md';
152вҶ’    } else {
153вҶ’      // Neither exists - default to index.md and let validation catch it
154вҶ’      repoRelative = repoRelative.endsWith('/') ? repoRelative + 'index.md' : repoRelative + '/index.md';
155вҶ’    }
156вҶ’  } else if (!repoRelative.endsWith('.md')) {
157вҶ’    // Path doesn't end with .md - add .md
158вҶ’    repoRelative = repoRelative + '.md';
159вҶ’  }
160вҶ’
161вҶ’  return repoRelative + query + anchor;
162вҶ’}
163вҶ’
164вҶ’/**
165вҶ’ * Process a single markdown file, skipping links inside fenced code blocks
166вҶ’ *
167вҶ’ * @param {string} filePath - Absolute path to the file
168вҶ’ * @returns {Object} - { changed: boolean, original: string, updated: string, changes: Array }
169вҶ’ */
170вҶ’function processFile(filePath) {
171вҶ’  const original = fs.readFileSync(filePath, 'utf-8');
172вҶ’  const changes = [];
173вҶ’
174вҶ’  // Extract fenced code blocks and replace with placeholders
175вҶ’  const codeBlocks = [];
176вҶ’  const CODE_PLACEHOLDER = '\u0000CODE_BLOCK_';
177вҶ’
178вҶ’  let contentWithPlaceholders = original.replaceAll(/```[\s\S]*?```/g, (match) => {
179вҶ’    const index = codeBlocks.length;
180вҶ’    codeBlocks.push(match);
181вҶ’    return `${CODE_PLACEHOLDER}${index}\u0000`;
182вҶ’  });
183вҶ’
184вҶ’  // Process links only in non-code-block content
185вҶ’  contentWithPlaceholders = contentWithPlaceholders.replaceAll(ALL_MARKDOWN_LINKS_REGEX, (match, linkText, href) => {
186вҶ’    const newHref = convertToRepoRelative(href, filePath);
187вҶ’
188вҶ’    // Skip if conversion returned null (external link, anchor, etc.)
189вҶ’    if (newHref === null) {
190вҶ’      return match;
191вҶ’    }
192вҶ’
193вҶ’    // Only record as change if actually different
194вҶ’    if (newHref !== href) {
195вҶ’      changes.push({ from: href, to: newHref });
196вҶ’      return `[${linkText}](${newHref})`;
197вҶ’    }
198вҶ’
199вҶ’    return match;
200вҶ’  });
201вҶ’
202вҶ’  // Restore code blocks
203вҶ’  const updated = contentWithPlaceholders.replaceAll(
204вҶ’    new RegExp(`${CODE_PLACEHOLDER}(\\d+)\u0000`, 'g'),
205вҶ’    (match, index) => codeBlocks[parseInt(index, 10)],
206вҶ’  );
207вҶ’
208вҶ’  return {
209вҶ’    changed: changes.length > 0,
210вҶ’    original,
211вҶ’    updated,
212вҶ’    changes,
213вҶ’  };
214вҶ’}
215вҶ’
216вҶ’/**
217вҶ’ * Validate that a repo-relative link points to an existing file
218вҶ’ */
219вҶ’function validateLink(repoRelativePath) {
220вҶ’  // Strip anchor/query
221вҶ’  const checkPath = repoRelativePath.split('#')[0].split('?')[0];
222вҶ’
223вҶ’  // Remove /docs/ prefix to get path relative to DOCS_ROOT
224вҶ’  const relativePath = checkPath.startsWith('/docs/') ? checkPath.slice(6) : checkPath.slice(1);
225вҶ’
226вҶ’  return fs.existsSync(path.join(DOCS_ROOT, relativePath));
227вҶ’}
228вҶ’
229вҶ’// Main execution
230вҶ’console.log(`\nScanning docs in: ${DOCS_ROOT}`);
231вҶ’console.log(`Mode: ${DRY_RUN ? 'DRY RUN (use --write to apply changes)' : 'WRITE MODE'}\n`);
232вҶ’
233вҶ’const files = getMarkdownFiles(DOCS_ROOT);
234вҶ’console.log(`Found ${files.length} markdown files (excluding _* paths)\n`);
235вҶ’
236вҶ’let totalChanges = 0;
237вҶ’let filesChanged = 0;
238вҶ’const brokenLinks = [];
239вҶ’
240вҶ’for (const filePath of files) {
241вҶ’  const relativePath = path.relative(DOCS_ROOT, filePath);
242вҶ’  const result = processFile(filePath);
243вҶ’
244вҶ’  if (result.changed) {
245вҶ’    filesChanged++;
246вҶ’    totalChanges += result.changes.length;
247вҶ’
248вҶ’    console.log(`\n${relativePath}`);
249вҶ’    for (const change of result.changes) {
250вҶ’      const isValid = validateLink(change.to);
251вҶ’      const status = isValid ? '  ' : '! ';
252вҶ’
253вҶ’      console.log(`${status}  ${change.from}`);
254вҶ’      console.log(`    -> ${change.to}`);
255вҶ’
256вҶ’      if (!isValid) {
257вҶ’        brokenLinks.push({
258вҶ’          file: relativePath,
259вҶ’          link: change.to,
260вҶ’          original: change.from,
261вҶ’        });
262вҶ’      }
263вҶ’    }
264вҶ’
265вҶ’    if (!DRY_RUN) {
266вҶ’      fs.writeFileSync(filePath, result.updated, 'utf-8');
267вҶ’    }
268вҶ’  }
269вҶ’}
270вҶ’
271вҶ’console.log(`\n${'в”Җ'.repeat(60)}`);
272вҶ’console.log(`\nSummary:`);
273вҶ’console.log(`   Files scanned: ${files.length}`);
274вҶ’console.log(`   Files with changes: ${filesChanged}`);
275вҶ’console.log(`   Total link updates: ${totalChanges}`);
276вҶ’
277вҶ’if (brokenLinks.length > 0) {
278вҶ’  console.log(`\n!  Potential broken links (${brokenLinks.length}):`);
279вҶ’  for (const bl of brokenLinks) {
280вҶ’    console.log(`   ${bl.file}: ${bl.link}`);
281вҶ’  }
282вҶ’}
283вҶ’
284вҶ’if (DRY_RUN && totalChanges > 0) {
285вҶ’  console.log(`\nRun with --write to apply these changes`);
286вҶ’}
287вҶ’
288вҶ’console.log('');
