 1вҶ’/**
 2вҶ’ * Rehype plugin to prepend base path to absolute URLs
 3вҶ’ *
 4вҶ’ * Transforms:
 5вҶ’ *   /img/foo.png вҶ’ /BMAD-METHOD/img/foo.png (when base is /BMAD-METHOD/)
 6вҶ’ *   /downloads/file.zip вҶ’ /BMAD-METHOD/downloads/file.zip
 7вҶ’ *   /llms.txt вҶ’ /BMAD-METHOD/llms.txt
 8вҶ’ *
 9вҶ’ * Only affects absolute paths (/) - relative paths and external URLs are unchanged.
10вҶ’ * Does NOT process .md links (those are handled by rehype-markdown-links).
11вҶ’ */
12вҶ’
13вҶ’import { visit } from 'unist-util-visit';
14вҶ’
15вҶ’/**
16вҶ’ * Create a rehype plugin that prepends the base path to absolute URLs.
17вҶ’ *
18вҶ’ * @param {Object} options - Plugin options
19вҶ’ * @param {string} options.base - The base path to prepend (e.g., '/BMAD-METHOD/')
20вҶ’ * @returns {function} A HAST tree transformer
21вҶ’ */
22вҶ’export default function rehypeBasePaths(options = {}) {
23вҶ’  const base = options.base || '/';
24вҶ’
25вҶ’  // Normalize base: ensure it ends with / and doesn't have double slashes
26вҶ’  const normalizedBase = base === '/' ? '/' : base.endsWith('/') ? base : base + '/';
27вҶ’
28вҶ’  return (tree) => {
29вҶ’    visit(tree, 'element', (node) => {
30вҶ’      // Process img tags with src attribute
31вҶ’      if (node.tagName === 'img' && node.properties?.src) {
32вҶ’        const src = node.properties.src;
33вҶ’
34вҶ’        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
35вҶ’          // Don't transform if already has the base path
36вҶ’          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
37вҶ’            node.properties.src = normalizedBase + src.slice(1);
38вҶ’          }
39вҶ’        }
40вҶ’      }
41вҶ’
42вҶ’      // Process iframe tags with src attribute
43вҶ’      if (node.tagName === 'iframe' && node.properties?.src) {
44вҶ’        const src = node.properties.src;
45вҶ’
46вҶ’        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
47вҶ’          // Don't transform if already has the base path
48вҶ’          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
49вҶ’            node.properties.src = normalizedBase + src.slice(1);
50вҶ’          }
51вҶ’        }
52вҶ’      }
53вҶ’
54вҶ’      // Process anchor tags with href attribute
55вҶ’      if (node.tagName === 'a' && node.properties?.href) {
56вҶ’        const href = node.properties.href;
57вҶ’
58вҶ’        if (typeof href !== 'string') {
59вҶ’          return;
60вҶ’        }
61вҶ’
62вҶ’        // Only transform absolute paths starting with / (but not //)
63вҶ’        if (!href.startsWith('/') || href.startsWith('//')) {
64вҶ’          return;
65вҶ’        }
66вҶ’
67вҶ’        // Skip if already has the base path
68вҶ’        if (normalizedBase !== '/' && href.startsWith(normalizedBase)) {
69вҶ’          return;
70вҶ’        }
71вҶ’
72вҶ’        // Skip .md links - those are handled by rehype-markdown-links
73вҶ’        // Extract path portion (before ? and #)
74вҶ’        const firstDelimiter = Math.min(
75вҶ’          href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
76вҶ’          href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
77вҶ’        );
78вҶ’        const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
79вҶ’
80вҶ’        if (pathPortion.endsWith('.md')) {
81вҶ’          return; // Let rehype-markdown-links handle this
82вҶ’        }
83вҶ’
84вҶ’        // Prepend base path
85вҶ’        node.properties.href = normalizedBase + href.slice(1);
86вҶ’      }
87вҶ’    });
88вҶ’  };
89вҶ’}
90вҶ’

  1вҶ’/**
  2вҶ’ * BMAD Method Documentation - Custom Styles for Starlight
  3вҶ’ * Electric Blue theme optimized for dark mode
