 32вҶ’  --sl-color-gray-4: #94a3b8;
 33вҶ’  --sl-color-gray-5: #cbd5e1;
 34вҶ’  --sl-color-gray-6: #e2e8f0;
 35вҶ’  --sl-color-black: #f8fafc;
 36вҶ’
 37вҶ’  /* Font settings */
 38вҶ’  --sl-font: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
 39вҶ’  --sl-text-base: 1rem;
 40вҶ’  --sl-line-height: 1.7;
 41вҶ’
 42вҶ’  /* Code highlighting */
 43вҶ’  --sl-color-bg-inline-code: rgba(140, 140, 255, 0.1);
 44вҶ’}
 45вҶ’
 46вҶ’/* ============================================
 47вҶ’   COLOR PALETTE - Dark Mode (Primary Focus)
 48вҶ’   ============================================ */
 49вҶ’:root[data-theme='dark'] {
 50вҶ’  /* Full-width content - override Starlight's default */
 51вҶ’  --sl-content-width: 100%;
 52вҶ’
 53вҶ’  /* Primary accent colors - purple to match Docusaurus */
