 60вҶ’  --sl-color-bg-nav: #1b1b1d;
 61вҶ’  --sl-color-bg-sidebar: #1b1b1d;
 62вҶ’  --sl-color-hairline-light: rgba(140, 140, 255, 0.1);
 63вҶ’  --sl-color-hairline: rgba(140, 140, 255, 0.15);
 64вҶ’
 65вҶ’  /* Text colors */
