 67вҶ’  --sl-color-gray-1: #e2e8f0;
 68вҶ’  --sl-color-gray-2: #cbd5e1;
 69вҶ’  --sl-color-gray-3: #94a3b8;
 70вҶ’  --sl-color-gray-4: #64748b;
