  1вҶ’/**
  2вҶ’ * TEA (Test Engineering Architect) Documentation Build Pipeline
  3вҶ’ *
  4вҶ’ * Consolidates docs from multiple sources, generates LLM-friendly files,
  5вҶ’ * creates downloadable bundles, and builds the Astro+Starlight site.
  6вҶ’ *
  7вҶ’ * Build outputs:
  8вҶ’ *   build/artifacts/     - With llms.txt, llms-full.txt, ZIPs
  9вҶ’ *   build/site/          - Final Astro output (deployable)
 10вҶ’ */
 11вҶ’
 12вҶ’const { execSync } = require('node:child_process');
 13вҶ’const fs = require('node:fs');
 14вҶ’const path = require('node:path');
 15вҶ’const archiver = require('archiver');
 16вҶ’
 17вҶ’// =============================================================================
 18вҶ’// Configuration
 19вҶ’// =============================================================================
 20вҶ’
 21вҶ’const PROJECT_ROOT = path.dirname(__dirname);
 22вҶ’const BUILD_DIR = path.join(PROJECT_ROOT, 'build');
 23вҶ’
 24вҶ’const SITE_URL = process.env.SITE_URL || 'https://test-architect.bmad-method.org';
 25вҶ’const REPO_URL = 'https://github.com/bmad-code-org/bmad-method-test-architecture-enterprise';
 26вҶ’
 27вҶ’// DO NOT CHANGE THESE VALUES!
 28вҶ’// llms-full.txt is consumed by AI agents as context. Most LLMs have ~200k token limits.
 29вҶ’// 600k chars вүҲ 150k tokens (safe margin). Exceeding this breaks AI agent functionality.
 30вҶ’const LLM_MAX_CHARS = 600_000;
 31вҶ’const LLM_WARN_CHARS = 500_000;
 32вҶ’
 33вҶ’const LLM_EXCLUDE_PATTERNS = [
 34вҶ’  'changelog',
 35вҶ’  'downloads/',
 36вҶ’  'reference/glossary/',
 37вҶ’  // Note: Files/dirs starting with _ (like _STYLE_GUIDE.md, _archive/) are excluded in shouldExcludeFromLlm()
 38вҶ’];
 39вҶ’
 40вҶ’// =============================================================================
 41вҶ’// Main Entry Point
 42вҶ’/**
 43вҶ’ * Orchestrates the full BMAD documentation build pipeline.
 44вҶ’ *
 45вҶ’ * Executes the high-level build steps in sequence: prints headers and paths, validates internal
 46вҶ’ * documentation links, cleans the build directory, generates artifacts from the `docs/` folder,
 47вҶ’ * builds the Astro site, and prints a final build summary.
 48вҶ’ */
 49вҶ’
 50вҶ’async function main() {
 51вҶ’  console.log();
 52вҶ’  printBanner('TEA Documentation Build Pipeline');
 53вҶ’  console.log();
 54вҶ’  console.log(`Project root: ${PROJECT_ROOT}`);
 55вҶ’  console.log(`Build directory: ${BUILD_DIR}`);
 56вҶ’  console.log();
 57вҶ’
 58вҶ’  // Check for broken internal links before building
 59вҶ’  checkDocLinks();
 60вҶ’
 61вҶ’  cleanBuildDirectory();
 62вҶ’
 63вҶ’  const docsDir = path.join(PROJECT_ROOT, 'docs');
 64вҶ’  const artifactsDir = await generateArtifacts(docsDir);
 65вҶ’  const siteDir = buildAstroSite();
 66вҶ’
 67вҶ’  printBuildSummary(docsDir, artifactsDir, siteDir);
 68вҶ’}
 69вҶ’
 70вҶ’main().catch((error) => {
 71вҶ’  console.error(error);
 72вҶ’  process.exit(1);
 73вҶ’});
 74вҶ’
 75вҶ’// =============================================================================
 76вҶ’// Pipeline Stages
 77вҶ’/**
 78вҶ’ * Generate LLM files and downloadable bundles for the documentation pipeline.
 79вҶ’ *
 80вҶ’ * Creates the build/artifacts directory, writes `llms.txt` and `llms-full.txt` (sourced from the provided docs directory),
 81вҶ’ * and produces download ZIP bundles.
 82вҶ’ *
 83вҶ’ * @param {string} docsDir - Path to the source docs directory containing Markdown files.
 84вҶ’ * @returns {string} Path to the created artifacts directory.
 85вҶ’ */
 86вҶ’
 87вҶ’async function generateArtifacts(docsDir) {
 88вҶ’  printHeader('Generating LLM files and download bundles');
 89вҶ’
 90вҶ’  const outputDir = path.join(BUILD_DIR, 'artifacts');
 91вҶ’  fs.mkdirSync(outputDir, { recursive: true });
 92вҶ’
 93вҶ’  // Generate LLM files reading from docs/, output to artifacts/
 94вҶ’  generateLlmsTxt(outputDir);
 95вҶ’  generateLlmsFullTxt(docsDir, outputDir);
 96вҶ’  await generateDownloadBundles(outputDir);
 97вҶ’
 98вҶ’  console.log();
 99вҶ’  console.log(`  \u001B[32mвң“\u001B[0m Artifact generation complete`);
100вҶ’
101вҶ’  return outputDir;
102вҶ’}
103вҶ’
104вҶ’/**
105вҶ’ * Builds the Astro + Starlight site and copies generated artifacts into the site output directory.
106вҶ’ *
107вҶ’ * @returns {string} The filesystem path to the built site directory (e.g., build/site).
108вҶ’ */
109вҶ’function buildAstroSite() {
110вҶ’  printHeader('Building Astro + Starlight site');
111вҶ’
112вҶ’  const siteDir = path.join(BUILD_DIR, 'site');
113вҶ’  const artifactsDir = path.join(BUILD_DIR, 'artifacts');
114вҶ’
115вҶ’  // Build Astro site (outputs to build/site via astro.config.mjs)
116вҶ’  runAstroBuild();
117вҶ’  copyArtifactsToSite(artifactsDir, siteDir);
118вҶ’
119вҶ’  // No longer needed: Inject AI agents banner into every HTML page
120вҶ’  // injectAgentBanner(siteDir);
121вҶ’
122вҶ’  console.log();
123вҶ’  console.log(`  \u001B[32mвң“\u001B[0m Astro build complete`);
124вҶ’
125вҶ’  return siteDir;
126вҶ’}
127вҶ’
128вҶ’// =============================================================================
129вҶ’// LLM File Generation
130вҶ’/**
131вҶ’ * Create a concise llms.txt summary file containing project metadata, core links, and quick navigation entries for LLM consumption.
132вҶ’ *
133вҶ’ * Writes the file to `${outputDir}/llms.txt`.
134вҶ’ *
135вҶ’ * @param {string} outputDir - Destination directory where `llms.txt` will be written.
136вҶ’ */
137вҶ’
138вҶ’function generateLlmsTxt(outputDir) {
139вҶ’  console.log('  вҶ’ Generating llms.txt...');
140вҶ’
141вҶ’  const content = [
142вҶ’    '# Test Architect (TEA) Documentation',
143вҶ’    '',
144вҶ’    '> Risk-based test strategy, automation guidance, and release gate decisions for quality-driven development.',
145вҶ’    '',
146вҶ’    `Documentation: ${SITE_URL}`,
147вҶ’    `Repository: ${REPO_URL}`,
148вҶ’    `Full docs: ${SITE_URL}/llms-full.txt`,
149вҶ’    '',
150вҶ’    '## Quick Start',
151вҶ’    '',
152вҶ’    `- **[TEA Lite Quickstart](${SITE_URL}/docs/tutorials/tea-lite-quickstart)** - Get started in 30 minutes`,
153вҶ’    `- **[Installation](${SITE_URL}/)** - Installation guide`,
154вҶ’    '',
155вҶ’    '## Core Workflows',
156вҶ’    '',
157вҶ’    `- **[Test Design (TD)](${SITE_URL}/docs/how-to/workflows/run-test-design)** - Risk-based test planning`,
158вҶ’    `- **[ATDD (AT)](${SITE_URL}/docs/how-to/workflows/run-atdd)** - Failing acceptance tests first`,
159вҶ’    `- **[Automate (TA)](${SITE_URL}/docs/how-to/workflows/run-automate)** - Expand automation coverage`,
160вҶ’    `- **[Trace (TR)](${SITE_URL}/docs/how-to/workflows/run-trace)** - Requirements traceability`,
161вҶ’    '',
162вҶ’    '## Additional Workflows',
163вҶ’    '',
164вҶ’    `- **[Framework (TF)](${SITE_URL}/docs/how-to/workflows/setup-test-framework)** - Scaffold test framework`,
165вҶ’    `- **[CI (CI)](${SITE_URL}/docs/how-to/workflows/setup-ci)** - CI/CD quality pipeline`,
166вҶ’    `- **[Test Review (RV)](${SITE_URL}/docs/how-to/workflows/run-test-review)** - Quality audit`,
167вҶ’    `- **[NFR Assess (NR)](${SITE_URL}/docs/how-to/workflows/run-nfr-assess)** - Non-functional requirements`,
168вҶ’    '',
169вҶ’    '---',
170вҶ’    '',
171вҶ’    '## Quick Links',
172вҶ’    '',
173вҶ’    `- [Full Documentation (llms-full.txt)](${SITE_URL}/llms-full.txt) - Complete docs for AI context`,
174вҶ’    `- [Source Bundle](${SITE_URL}/downloads/tea-sources.zip) - Complete source code`,
175вҶ’    `- [Prompts Bundle](${SITE_URL}/downloads/tea-prompts.zip) - Agent prompts and workflows`,
176вҶ’    '',
177вҶ’  ].join('\n');
178вҶ’
179вҶ’  const outputPath = path.join(outputDir, 'llms.txt');
180вҶ’  fs.writeFileSync(outputPath, content, 'utf-8');
181вҶ’  console.log(`    Generated llms.txt (${content.length.toLocaleString()} chars)`);
182вҶ’}
183вҶ’
184вҶ’/**
185вҶ’ * Builds a consolidated llms-full.txt containing all Markdown files under docsDir wrapped in <document path="..."> tags for LLM consumption.
186вҶ’ *
187вҶ’ * Writes the generated file to outputDir/llms-full.txt. Files matching LLM_EXCLUDE_PATTERNS are skipped; read errors for individual files are logged. The combined content is validated against configured size thresholds (will exit on overflow and warn if near limit).
188вҶ’ * @param {string} docsDir - Root directory containing source Markdown files; paths in the output are relative to this directory.
189вҶ’ * @param {string} outputDir - Directory where llms-full.txt will be written.
190вҶ’ */
191вҶ’function generateLlmsFullTxt(docsDir, outputDir) {
192вҶ’  console.log('  вҶ’ Generating llms-full.txt...');
193вҶ’
194вҶ’  const date = new Date().toISOString().split('T')[0];
195вҶ’  const files = getAllMarkdownFiles(docsDir);
196вҶ’
197вҶ’  const output = [
198вҶ’    '# Test Architect (TEA) Documentation (Full)',
199вҶ’    '',
200вҶ’    '> Complete documentation for AI consumption',
201вҶ’    `> Generated: ${date}`,
202вҶ’    `> Repository: ${REPO_URL}`,
203вҶ’    '',
204вҶ’  ];
205вҶ’
206вҶ’  let fileCount = 0;
207вҶ’  let skippedCount = 0;
208вҶ’
209вҶ’  for (const mdPath of files) {
210вҶ’    if (shouldExcludeFromLlm(mdPath)) {
211вҶ’      skippedCount++;
212вҶ’      continue;
213вҶ’    }
214вҶ’
215вҶ’    const fullPath = path.join(docsDir, mdPath);
216вҶ’    try {
217вҶ’      const content = readMarkdownContent(fullPath);
218вҶ’      output.push(`<document path="${mdPath}">`, content, '</document>', '');
219вҶ’      fileCount++;
220вҶ’    } catch (error) {
221вҶ’      console.error(`    Warning: Could not read ${mdPath}: ${error.message}`);
222вҶ’    }
223вҶ’  }
224вҶ’
225вҶ’  const result = output.join('\n');
226вҶ’  validateLlmSize(result);
227вҶ’
228вҶ’  const outputPath = path.join(outputDir, 'llms-full.txt');
229вҶ’  fs.writeFileSync(outputPath, result, 'utf-8');
230вҶ’
231вҶ’  const tokenEstimate = Math.floor(result.length / 4).toLocaleString();
232вҶ’  console.log(
233вҶ’    `    Processed ${fileCount} files (skipped ${skippedCount}), ${result.length.toLocaleString()} chars (~${tokenEstimate} tokens)`,
234вҶ’  );
235вҶ’}
236вҶ’
237вҶ’/**
238вҶ’ * Collects all Markdown (.md) files under a directory and returns their paths relative to a base directory.
239вҶ’ * @param {string} dir - Directory to search for Markdown files.
240вҶ’ * @param {string} [baseDir=dir] - Base directory used to compute returned relative paths.
241вҶ’ * @returns {string[]} An array of file paths (relative to `baseDir`) for every `.md` file found under `dir`.
242вҶ’ */
243вҶ’function getAllMarkdownFiles(dir, baseDir = dir) {
244вҶ’  const files = [];
245вҶ’
246вҶ’  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
247вҶ’    const fullPath = path.join(dir, entry.name);
248вҶ’
249вҶ’    if (entry.isDirectory()) {
250вҶ’      files.push(...getAllMarkdownFiles(fullPath, baseDir));
251вҶ’    } else if (entry.name.endsWith('.md')) {
252вҶ’      // Return relative path from baseDir
253вҶ’      const relativePath = path.relative(baseDir, fullPath);
254вҶ’      files.push(relativePath);
255вҶ’    }
256вҶ’  }
257вҶ’
258вҶ’  return files;
259вҶ’}
260вҶ’
261вҶ’/**
262вҶ’ * Determine whether a file path matches any configured LLM exclusion pattern.
263вҶ’ * Also excludes any files or directories starting with underscore.
264вҶ’ * @param {string} filePath - The file path to test.
265вҶ’ * @returns {boolean} `true` if excluded, `false` otherwise.
266вҶ’ */
267вҶ’function shouldExcludeFromLlm(filePath) {
268вҶ’  // Exclude if ANY path component starts with underscore
269вҶ’  // (e.g., _STYLE_GUIDE.md, _archive/file.md, dir/_STYLE_GUIDE.md)
270вҶ’  const pathParts = filePath.split(path.sep);
271вҶ’  if (pathParts.some((part) => part.startsWith('_'))) return true;
272вҶ’
273вҶ’  // Check configured patterns
274вҶ’  return LLM_EXCLUDE_PATTERNS.some((pattern) => filePath.includes(pattern));
275вҶ’}
276вҶ’
277вҶ’function readMarkdownContent(filePath) {
278вҶ’  let content = fs.readFileSync(filePath, 'utf-8');
279вҶ’
280вҶ’  if (content.startsWith('---')) {
281вҶ’    const end = content.indexOf('---', 3);
282вҶ’    if (end !== -1) {
283вҶ’      content = content.slice(end + 3).trim();
284вҶ’    }
285вҶ’  }
286вҶ’
287вҶ’  return content;
288вҶ’}
289вҶ’
290вҶ’function validateLlmSize(content) {
291вҶ’  const charCount = content.length;
292вҶ’
293вҶ’  if (charCount > LLM_MAX_CHARS) {
294вҶ’    console.error(`    ERROR: Exceeds ${LLM_MAX_CHARS.toLocaleString()} char limit`);
295вҶ’    process.exit(1);
296вҶ’  } else if (charCount > LLM_WARN_CHARS) {
297вҶ’    console.warn(`    \u001B[33mWARNING: Approaching ${LLM_WARN_CHARS.toLocaleString()} char limit\u001B[0m`);
298вҶ’  }
299вҶ’}
300вҶ’
301вҶ’// =============================================================================
302вҶ’// Download Bundle Generation
303вҶ’// =============================================================================
304вҶ’
305вҶ’async function generateDownloadBundles(outputDir) {
306вҶ’  console.log('  вҶ’ Generating download bundles...');
307вҶ’
308вҶ’  const downloadsDir = path.join(outputDir, 'downloads');
309вҶ’  fs.mkdirSync(downloadsDir, { recursive: true });
310вҶ’
311вҶ’  await generateSourcesBundle(downloadsDir);
312вҶ’  await generatePromptsBundle(downloadsDir);
313вҶ’}
314вҶ’
315вҶ’async function generateSourcesBundle(downloadsDir) {
316вҶ’  const srcDir = path.join(PROJECT_ROOT, 'src');
317вҶ’  if (!fs.existsSync(srcDir)) return;
318вҶ’
319вҶ’  const zipPath = path.join(downloadsDir, 'tea-sources.zip');
320вҶ’  await createZipArchive(srcDir, zipPath, ['__pycache__', '.pyc', '.DS_Store', 'node_modules']);
321вҶ’
322вҶ’  const size = (fs.statSync(zipPath).size / 1024 / 1024).toFixed(1);
323вҶ’  console.log(`    tea-sources.zip (${size}M)`);
324вҶ’}
325вҶ’
326вҶ’/**
327вҶ’ * Create a zip archive of the project's prompts (agents and workflows) and place it in the downloads directory.
328вҶ’ *
329вҶ’ * Creates tea-prompts.zip from src/ (agents, workflows, testarch), excluding common unwanted paths, writes it to the provided downloads directory, and logs the resulting file size. If src directory does not exist, the function returns without creating a bundle.
330вҶ’ * @param {string} downloadsDir - Destination directory where tea-prompts.zip will be written.
331вҶ’ */
332вҶ’async function generatePromptsBundle(downloadsDir) {
333вҶ’  const srcDir = path.join(PROJECT_ROOT, 'src');
334вҶ’  if (!fs.existsSync(srcDir)) return;
335вҶ’
336вҶ’  const zipPath = path.join(downloadsDir, 'tea-prompts.zip');
337вҶ’  await createZipArchive(srcDir, zipPath, ['docs', '.DS_Store', '__pycache__', 'node_modules']);
338вҶ’
339вҶ’  const size = Math.floor(fs.statSync(zipPath).size / 1024);
340вҶ’  console.log(`    tea-prompts.zip (${size}K)`);
341вҶ’}
342вҶ’
343вҶ’// =============================================================================
344вҶ’// Astro Build
345вҶ’/**
346вҶ’ * Builds the Astro site to build/site (configured in astro.config.mjs).
347вҶ’ */
348вҶ’function runAstroBuild() {
349вҶ’  console.log('  вҶ’ Running astro build...');
350вҶ’  execSync('npx astro build --root website', {
351вҶ’    cwd: PROJECT_ROOT,
352вҶ’    stdio: 'inherit',
353вҶ’    env: {
354вҶ’      ...process.env,
355вҶ’    },
356вҶ’  });
357вҶ’}
358вҶ’
359вҶ’/**
360вҶ’ * Copy generated artifact files into the built site directory.
361вҶ’ *
362вҶ’ * Copies llms.txt and llms-full.txt from the artifacts directory into the site directory.
363вҶ’ * If a downloads subdirectory exists under artifacts, copies it into siteDir/downloads.
364вҶ’ *
365вҶ’ * @param {string} artifactsDir - Path to the build artifacts directory containing generated files.
366вҶ’ * @param {string} siteDir - Path to the target site directory where artifacts should be placed.
367вҶ’ */
368вҶ’function copyArtifactsToSite(artifactsDir, siteDir) {
369вҶ’  console.log('  вҶ’ Copying artifacts to site...');
370вҶ’
371вҶ’  fs.copyFileSync(path.join(artifactsDir, 'llms.txt'), path.join(siteDir, 'llms.txt'));
372вҶ’  fs.copyFileSync(path.join(artifactsDir, 'llms-full.txt'), path.join(siteDir, 'llms-full.txt'));
373вҶ’
374вҶ’  const downloadsDir = path.join(artifactsDir, 'downloads');
375вҶ’  if (fs.existsSync(downloadsDir)) {
376вҶ’    copyDirectory(downloadsDir, path.join(siteDir, 'downloads'));
377вҶ’  }
378вҶ’}
379вҶ’
380вҶ’// =============================================================================
381вҶ’// Build Summary
382вҶ’/**
383вҶ’ * Prints a concise end-of-build summary and displays a sample listing of the final site directory.
384вҶ’ *
385вҶ’ * @param {string} docsDir - Path to the source documentation directory used for the build.
386вҶ’ * @param {string} artifactsDir - Path to the directory containing generated artifacts (e.g., llms.txt, downloads).
